#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char ci, pi;
        char rules[128];
        for (int i = 0; i < 128; i++) {
            rules[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            scanf(" %c %c", &ci, &pi);
            rules[ci] = pi;
        }
        char S[1000001];
        scanf("%s", S);
        for (int i = 0; i < strlen(S); i++) {
            if (rules[S[i]]) {
                S[i] = rules[S[i]];
            }
        }
        if (S[0] == '0' && strchr(S, '.') == NULL) {
            S = S + strlen(S) - strlen(strchr(S, '0'));
            if (S[0] == '0') {
                printf("0\n");
            } else {
                printf("%s\n", S);
            }
        } else if (strchr(S, '.') != NULL) {
            char *ptr = S + strlen(S) - 1;
            while (*ptr == '0') {
                *ptr = '0';
                ptr--;
            }
            if (S[strlen(S) - 1] == '.') {
                S[strlen(S) - 1] = '0';
            }
            if (S[0] == '0') {
                printf("0\n");
            } else {
                printf("%s\n", S);
            }
        } else {
            printf("%s\n", S);
        }
    }
    return 0;
}

