import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            char ci, pi;
            char[] rules = new char[128];
            for (int i = 0; i < 128; i++) {
                rules[i] = 0;
            }
            for (int i = 0; i < N; i++) {
                ci = sc.next().charAt(0);
                pi = sc.next().charAt(0);
                rules[ci] = pi;
            }
            String S = sc.next();
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < S.length(); i++) {
                if (rules[S.charAt(i)] != 0) {
                    sb.append(rules[S.charAt(i)]);
                } else {
                    sb.append(S.charAt(i));
                }
            }
            S = sb.toString();
            if (S.charAt(0) == '0' && !S.contains(".")) {
                S = S.replaceAll("^0+", "");
                if (S.isEmpty()) {
                    System.out.println("0");
                } else {
                    System.out.println(S);
                }
            } else if (S.contains(".")) {
                S = S.replaceAll("0+$", "");
                if (S.endsWith(".")) {
                    S = S.substring(0, S.length() - 1);
                }
                if (S.isEmpty()) {
                    System.out.println("0");
                } else {
                    System.out.println(S);
                }
            } else {
                System.out.println(S);
            }
        }
    }
}

