const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const rules = {};
    for (let j = 0; j < N; j++) {
        const [ci, pi] = readline().split(' ');
        rules[ci] = pi;
    }
    const S = readline();
    let result = '';
    for (let k = 0; k < S.length; k++) {
        if (rules[S[k]]) {
            result += rules[S[k]];
        } else {
            result += S[k];
        }
    }
    if (result[0] === '0' && !result.includes('.')) {
        result = result.replace(/^0+/, '') || '0';
    } else if (result.includes('.')) {
        result = result.replace(/0+$/, '').replace(/\.$/, '') || '0';
    }
    console.log(result);
}

